import React from "react";
import classes from './Post.module.css';

const Post = (props) => {
    return <div className={classes.item}>
        <img className={classes.itemimg} src='https://avatarko.ru/img/kartinka/24/zhivotnye_kot_computer_23354.jpg' alt='Аватар'/>
        <img className={classes.itemimg} src={props.profile.photos.small} alt='Аватар'/>

        <div className={classes.posts}>
            {props.post}
            <div>Like: {props.likesCount}</div>
        </div>
           </div>
}

export default Post;
